mapper.select:
SELECT id, spu_id, sku_code, sku_name, item_type, length_mm, width_mm, thickness_mm, roll_length_m, color, gsm, status, deleted, created_at, updated_at, created_by, updated_by FROM sku WHERE deleted = 0
AND (sku_name LIKE CONCAT('%', #{keyword}, '%') OR sku_code LIKE CONCAT('%', #{keyword}, '%'))
AND spu_id = #{spuId}
AND item_type = #{itemType}
AND status = #{status}
ORDER BY created_at DESC, id DESC
